// export default class dataBase {
import Post from '../Post'

export function openDataBase(data) {
    let openReq = indexedDB.open("Post_User_DB", 15)
    let db;
    let transaction;

    openReq.onupgradeneeded = function (e) {
        db = e.target.result;
        if (!db.objectStoreNames.contains("post")) {
            db.createObjectStore("post")
        }
        if (!db.objectStoreNames.contains("user-post-1")) {
            db.createObjectStore("user-post-1")
        }
        
    }

    openReq.onsuccess = function (e) {
        console.log("Success!");
        console.log();

        db = e.target.result;
        transaction = db.transaction(["post"],"readwrite");
        const store1 = transaction.objectStore("post");
        for (let i = 0; i < Post.length; i++) {
            store1.add(Post[i], i).onsuccess = e => console.log(e);
        }
    }
    openReq.onerror = function (e) {
        console.log("Error");
        console.dir(e);
    }
}

export function readDataBase(arr) {

    arr.push(1)
}
